本篇概述什么是数据结构、数据结构与算法的关系以及相关概念术语。 

一、概述二、笔记三、习题&ensp;&ensp; &ensp; 1. 最大子列和问题&ensp;&ensp; &ensp; 给定 N 个整数的序列 {$A_1, A_2, … ,A_N$}，求函数 $ \sum\limits_{k=i}^j A_k $ 最大值。

方法一：穷举法int MaxSubSeqSum1(int List[], int N) &#123;
    int ThisSum, MaxSum;
    for (int i = 0; i &lt; N; i++) &#123;        // i 为子列左端
        ThisSum = 0;
        for (int j = i; j &lt; N; j++) &#123;    // j 为子列右端
            ThisSum += List[j];
            if (ThisSum > MaxSum)
                MaxSum = ThisSum;
        &#125;
    &#125;
    return MaxSum;
&#125;
方法二：分治法int Max3(int A, int B, int C) &#123;
  return (A > B) ? (A > C ? A : C) : (B > C ? B : C);
&#125;

int DivideAndConquer(int List[], int left, int right) &#123;
  int MaxLeftSum, MaxRightSum;              // 左右子问题解
  int MaxLeftBorderSum, MaxRightBorderSum;  // 跨跃分界线解

  int LeftBorderSum, RightBorderSum;
  int center, i;

  // 递归终止
  if (left == right) &#123;
    if (List[Left] > 0)&#123;
      return List[Left];
    &#125; else &#123;
      return 0;
    &#125;
  &#125;

  // 分治
  center = (left + right) / 2;
  MaxLeftSum = DivideAndConquer(List, Left, center);
  MaxRightSum = DivideAndConquer(List, center+1, right)

  // 求跨界的最大子列和
  MaxLeftBorderSum = 0; LeftBorderSum = 0;
  for (int i = center; i >= left; i++) &#123;
    LeftBorderSum += List[i];
    if (LeftBorderSum > MaxLeftBorderSum)&#123;
      MaxLeftBorderSum = LeftBorderSum;
    &#125;
  &#125;  // 左边扫描结束

  MaxRightBorderSum = 0; RightBorderSum = 0;
  for (int i = center + 1; i &lt;= right; i++) &#123;
    RightBorderSum += List[i];
    if (RightBorderSum > MaxRightBorderSum) &#123;
      MaxRightBorderSum = RightBorderSum;
    &#125;
  &#125;  // 右边扫描结束

  return Max3(MaxLeftSum, MaxRightSum, MaxLeftBorderSum + MaxRightBorderSum);
&#125;

int MaxSubSeqSum2(int List[], int N) &#123;
  return DivideAndConquer(List, 0, N - 1);
&#125;
方法三：联机法int MaxSubSeqSum3(int List[], int N) &#123;
  int ThisSum = MaxSum = 0;
  for (int i = 0; i &lt; N; i++) &#123;
    ThisSum += List[i];
    if (ThisSum > MaxSum) &#123;
      MaxSum = ThisSum;
    &#125; else if (ThisSum &lt; 0) &#123;
      ThisSum = 0;
    &#125;
  &#125;
  return MaxSum;
&#125;


// Main 方法
#include &lt;stdio.h>
#define MAXN 100000    //本题最大数据是十万
int main(void) &#123;
    int K, i;
    int a[MAXN] = &#123;0&#125;;

    scanf("%d", &amp;K);
    for ( i = 0; i &lt; K; i++ )
        scanf("%d", &amp;a[i]);
    printf("%d", MaxSubseqSum4( a, K ));

    return 0;
&#125;
